     1→import DateTime, { friendlyDateTime } from "./datetime.js";
     2→import Duration from "./duration.js";
     3→import Settings from "./settings.js";
     4→import { InvalidArgumentError, InvalidIntervalError } from "./errors.js";
     5→import Invalid from "./impl/invalid.js";
     6→import Formatter from "./impl/formatter.js";
     7import * as Formats from "./impl/formats.js";
     8→
     9→const INVALID = "Invalid Interval";
    10→
    11→// checks if the start is equal to or before the end
    12→function validateStartEnd(start, end) {
    13→  if (!start || !start.isValid) {
    14→    return Interval.invalid("missing or invalid start");
    15→  } else if (!end || !end.isValid) {
    16→    return Interval.invalid("missing or invalid end");
    17→  } else if (end < start) {
    18→    return Interval.invalid(
    19→      "end before start",
    20→      `The end of an interval must be after its start, but you had start=${start.toISO()} and end=${end.toISO()}`
    21→    );
    22→  } else {
    23→    return null;
    24→  }
    25→}
    26→
    27→/**
    28→ * An Interval object represents a half-open interval of time, where each endpoint is a {@link DateTime}. Conceptually, it's a container for those two endpoints, accompanied by methods for creating, parsing, interrogating, comparing, transforming, and formatting them.
    29→ *
    30→ * Here is a brief overview of the most commonly used methods and getters in Interval:
    31→ *
    32→ * * **Creation** To create an Interval, use {@link Interval.fromDateTimes}, {@link Interval.after}, {@link Interval.before}, or {@link Interval.fromISO}.
    33→ * * **Accessors** Use {@link Interval#start} and {@link Interval#end} to get the start and end.
    34→ * * **Interrogation** To analyze the Interval, use {@link Interval#count}, {@link Interval#length}, {@link Interval#hasSame}, {@link Interval#contains}, {@link Interval#isAfter}, or {@link Interval#isBefore}.
    35→ * * **Transformation** To create other Intervals out of this one, use {@link Interval#set}, {@link Interval#splitAt}, {@link Interval#splitBy}, {@link Interval#divideEqually}, {@link Interval.merge}, {@link Interval.xor}, {@link Interval#union}, {@link Interval#intersection}, or {@link Interval#difference}.
    36→ * * **Comparison** To compare this Interval to another one, use {@link Interval#equals}, {@link Interval#overlaps}, {@link Interval#abutsStart}, {@link Interval#abutsEnd}, {@link Interval#engulfs}
    37→ * * **Output** To convert the Interval into other representations, see {@link Interval#toString}, {@link Interval#toLocaleString}, {@link Interval#toISO}, {@link Interval#toISODate}, {@link Interval#toISOTime}, {@link Interval#toFormat}, and {@link Interval#toDuration}.
    38→ */
    39→export default class Interval {
    40→  /**
    41→   * @private
    42→   */
    43→  constructor(config) {
    44→    /**
    45→     * @access private
    46→     */
    47→    this.s = config.start;
    48→    /**
    49→     * @access private
    50→     */
    51→    this.e = config.end;
    52→    /**
    53→     * @access private
    54→     */
    55→    this.invalid = config.invalid || null;
    56→    /**
    57→     * @access private
    58→     */
    59→    this.isLuxonInterval = true;
    60→  }
    61→
    62→  /**
    63→   * Create an invalid Interval.
    64→   * @param {string} reason - simple string of why this Interval is invalid. Should not contain parameters or anything else data-dependent
    65→   * @param {string} [explanation=null] - longer explanation, may include parameters and other useful debugging information
    66→   * @return {Interval}
    67→   */
    68→  static invalid(reason, explanation = null) {
    69→    if (!reason) {
    70→      throw new InvalidArgumentError("need to specify a reason the Interval is invalid");
    71→    }
    72→
    73→    const invalid = reason instanceof Invalid ? reason : new Invalid(reason, explanation);
    74→
    75→    if (Settings.throwOnInvalid) {
    76→      throw new InvalidIntervalError(invalid);
    77→    } else {
    78→      return new Interval({ invalid });
    79→    }
    80→  }
    81→
    82→  /**
    83→   * Create an Interval from a start DateTime and an end DateTime. Inclusive of the start but not the end.
    84→   * @param {DateTime|Date|Object} start
    85→   * @param {DateTime|Date|Object} end
    86→   * @return {Interval}
    87→   */
    88→  static fromDateTimes(start, end) {
    89→    const builtStart = friendlyDateTime(start),
    90→      builtEnd = friendlyDateTime(end);
    91→
    92→    const validateError = validateStartEnd(builtStart, builtEnd);
    93→
    94→    if (validateError == null) {
    95→      return new Interval({
    96→        start: builtStart,
    97→        end: builtEnd,
    98→      });
    99→    } else {
   100→      return validateError;
   101→    }
   102→  }
   103→
   104→  /**
   105→   * Create an Interval from a start DateTime and a Duration to extend to.
   106→   * @param {DateTime|Date|Object} start
   107→   * @param {Duration|Object|number} duration - the length of the Interval.
   108→   * @return {Interval}
   109→   */
   110→  static after(start, duration) {
   111→    const dur = Duration.fromDurationLike(duration),
   112→      dt = friendlyDateTime(start);
   113→    return Interval.fromDateTimes(dt, dt.plus(dur));
   114→  }
   115→
   116→  /**
   117→   * Create an Interval from an end DateTime and a Duration to extend backwards to.
   118→   * @param {DateTime|Date|Object} end
   119→   * @param {Duration|Object|number} duration - the length of the Interval.
   120→   * @return {Interval}
   121→   */
   122→  static before(end, duration) {
   123→    const dur = Duration.fromDurationLike(duration),
   124→      dt = friendlyDateTime(end);
   125→    return Interval.fromDateTimes(dt.minus(dur), dt);
   126→  }
   127→
   128→  /**
   129→   * Create an Interval from an ISO 8601 string.
   130→   * Accepts `<start>/<end>`, `<start>/<duration>`, and `<duration>/<end>` formats.
   131→   * @param {string} text - the ISO string to parse
   132→   * @param {Object} [opts] - options to pass {@link DateTime#fromISO} and optionally {@link Duration#fromISO}
   133→   * @see https://en.wikipedia.org/wiki/ISO_8601#Time_intervals
   134→   * @return {Interval}
   135→   */
   136→  static fromISO(text, opts) {
   137→    const [s, e] = (text || "").split("/", 2);
   138→    if (s && e) {
   139→      let start, startIsValid;
   140→      try {
   141→        start = DateTime.fromISO(s, opts);
   142→        startIsValid = start.isValid;
   143→      } catch (e) {
   144→        startIsValid = false;
   145→      }
   146→
   147→      let end, endIsValid;
   148→      try {
   149→        end = DateTime.fromISO(e, opts);
   150→        endIsValid = end.isValid;
   151→      } catch (e) {
   152→        endIsValid = false;
   153→      }
   154→
   155→      if (startIsValid && endIsValid) {
   156→        return Interval.fromDateTimes(start, end);
   157→      }
   158→
   159→      if (startIsValid) {
   160→        const dur = Duration.fromISO(e, opts);
   161→        if (dur.isValid) {
   162→          return Interval.after(start, dur);
   163→        }
   164→      } else if (endIsValid) {
   165→        const dur = Duration.fromISO(s, opts);
   166→        if (dur.isValid) {
   167→          return Interval.before(end, dur);
   168→        }
   169→      }
   170→    }
   171→    return Interval.invalid("unparsable", `the input "${text}" can't be parsed as ISO 8601`);
   172→  }
   173→
   174→  /**
   175→   * Check if an object is an Interval. Works across context boundaries
   176→   * @param {object} o
   177→   * @return {boolean}
   178→   */
   179→  static isInterval(o) {
   180→    return (o && o.isLuxonInterval) || false;
   181→  }
   182→
   183→  /**
   184→   * Returns the start of the Interval
   185→   * @type {DateTime}
   186→   */
   187→  get start() {
   188→    return this.isValid ? this.s : null;
   189→  }
   190→
   191→  /**
   192→   * Returns the end of the Interval. This is the first instant which is not part of the interval
   193→   * (Interval is half-open).
   194→   * @type {DateTime}
   195→   */
   196→  get end() {
   197→    return this.isValid ? this.e : null;
   198→  }
   199→
   200→  /**
   201→   * Returns the last DateTime included in the interval (since end is not part of the interval)
   202→   * @type {DateTime}
   203→   */
   204→  get lastDateTime() {
   205→    return this.isValid ? (this.e ? this.e.minus(1) : null) : null;
   206→  }
   207→
   208→  /**
   209→   * Returns whether this Interval's end is at least its start, meaning that the Interval isn't 'backwards'.
   210→   * @type {boolean}
   211→   */
   212→  get isValid() {
   213→    return this.invalidReason === null;
   214→  }
   215→
   216→  /**
   217→   * Returns an error code if this Interval is invalid, or null if the Interval is valid
   218→   * @type {string}
   219→   */
   220→  get invalidReason() {
   221→    return this.invalid ? this.invalid.reason : null;
   222→  }
   223→
   224→  /**
   225→   * Returns an explanation of why this Interval became invalid, or null if the Interval is valid
   226→   * @type {string}
   227→   */
   228→  get invalidExplanation() {
   229→    return this.invalid ? this.invalid.explanation : null;
   230→  }
   231→
   232→  /**
   233→   * Returns the length of the Interval in the specified unit.
   234→   * @param {string} unit - the unit (such as 'hours' or 'days') to return the length in.
   235→   * @return {number}
   236→   */
   237→  length(unit = "milliseconds") {
   238→    return this.isValid ? this.toDuration(...[unit]).get(unit) : NaN;
   239→  }
   240→
   241→  /**
   242→   * Returns the count of minutes, hours, days, months, or years included in the Interval, even in part.
   243→   * Unlike {@link Interval#length} this counts sections of the calendar, not periods of time, e.g. specifying 'day'
   244→   * asks 'what dates are included in this interval?', not 'how many days long is this interval?'
   245→   * @param {string} [unit='milliseconds'] - the unit of time to count.
   246→   * @param {Object} opts - options
   247→   * @param {boolean} [opts.useLocaleWeeks=false] - If true, use weeks based on the locale, i.e. use the locale-dependent start of the week; this operation will always use the locale of the start DateTime
   248→   * @return {number}
   249→   */
   250→  count(unit = "milliseconds", opts) {
   251→    if (!this.isValid) return NaN;
   252→    const start = this.start.startOf(unit, opts);
   253→    let end;
   254→    if (opts?.useLocaleWeeks) {
   255→      end = this.end.reconfigure({ locale: start.locale });
   256→    } else {
   257→      end = this.end;
   258→    }
   259→    end = end.startOf(unit, opts);
   260→    return Math.floor(end.diff(start, unit).get(unit)) + (end.valueOf() !== this.end.valueOf());
   261→  }
   262→
   263→  /**
   264→   * Returns whether this Interval's start and end are both in the same unit of time
   265→   * @param {string} unit - the unit of time to check sameness on
   266→   * @return {boolean}
   267→   */
   268→  hasSame(unit) {
   269→    return this.isValid ? this.isEmpty() || this.e.minus(1).hasSame(this.s, unit) : false;
   270→  }
   271→
   272→  /**
   273→   * Return whether this Interval has the same start and end DateTimes.
   274→   * @return {boolean}
   275→   */
   276→  isEmpty() {
   277→    return this.s.valueOf() === this.e.valueOf();
   278→  }
   279→
   280→  /**
   281→   * Return whether this Interval's start is after the specified DateTime.
   282→   * @param {DateTime} dateTime
   283→   * @return {boolean}
   284→   */
   285→  isAfter(dateTime) {
   286→    if (!this.isValid) return false;
   287→    return this.s > dateTime;
   288→  }
   289→
   290→  /**
   291→   * Return whether this Interval's end is before the specified DateTime.
   292→   * @param {DateTime} dateTime
   293→   * @return {boolean}
   294→   */
   295→  isBefore(dateTime) {
   296→    if (!this.isValid) return false;
   297→    return this.e <= dateTime;
   298→  }
   299→
   300→  /**
   301→   * Return whether this Interval contains the specified DateTime.
   302→   * @param {DateTime} dateTime
   303→   * @return {boolean}
   304→   */
   305→  contains(dateTime) {
   306→    if (!this.isValid) return false;
   307→    return this.s <= dateTime && this.e > dateTime;
   308→  }
   309→
   310→  /**
   311→   * "Sets" the start and/or end dates. Returns a newly-constructed Interval.
   312→   * @param {Object} values - the values to set
   313→   * @param {DateTime} values.start - the starting DateTime
   314→   * @param {DateTime} values.end - the ending DateTime
   315→   * @return {Interval}
   316→   */
   317→  set({ start, end } = {}) {
   318→    if (!this.isValid) return this;
   319→    return Interval.fromDateTimes(start || this.s, end || this.e);
   320→  }
   321→
   322→  /**
   323→   * Split this Interval at each of the specified DateTimes
